1590						res_pool->ref_clocks.xtalin_clock_inKhz;
1591				res_pool->ref_clocks.dchub_ref_clock_inKhz =
1592						res_pool->ref_clocks.xtalin_clock_inKhz;
1593			}
1594		} else
