3078	
3079			if (!pipe_ctx->top_pipe &&
3080				!pipe_ctx->prev_odm_pipe &&
3081				pipe_ctx->stream) {
3082				struct timing_generator *tg = pipe_ctx->stream_res.tg;
3083	
